'''
DAG-based job scheduler.

Job storage format: {id: {'fn': callable, 'deps': list[str], 'priority': int}}
Scheduler state:
  self.jobs: dict (Job definitions)
  self.results: dict (job_id -> result)
  self._is_run: bool (flag to know if results are stored/dirty)

Job: id, fn (callable), deps (list of job ids), priority (int, higher = first)
Scheduler:
  add_job(id, fn, deps=[], priority=0)
  run() -> dict[id, result]   executes jobs in dependency order,
                              breaking ties by priority (desc), then id
  get_result(id) -> any
  reset()  clear results, keep job definitions

Raises:
  CycleError   if dependency graph has a cycle
  ValueError   if a dependency id is unknown during add_job or runtime setup
'''

class CycleError(Exception):
    pass

class Scheduler:
    def __init__(self):
        # Stores job definitions: {id: {'fn': callable, 'deps': list[str], 'priority': int}}
        self.jobs = {}
        # Stores results: {job_id: result}
        self.results = {}

    def add_job(self, job_id, fn, deps=None, priority=0):
        if job_id in self.jobs:
            raise ValueError(f"Job ID '{job_id}' already exists.")

        deps = deps if deps is not None else []

        # Validate dependencies exist among added jobs (we wait until run() for full cycle checks)
        for dep_id in deps:
            if dep_id not in self.jobs and dep_id != job_id:
                # A slightly advanced check, but generally we only validate unknown deps later or during finalization.
                # For now, just storing it is enough until run().
                pass

        self.jobs[job_id] = {
            'fn': fn, 
            'deps': deps, 
            'priority': priority # Higher number means higher priority (runs first if dependencies met)
        }

    def _validate_dependencies(self):
        # Check for unknown dependency IDs and cycles simultaneously.

        # Phase 1: Unknown Dependencies
        all_jobs = set(self.jobs.keys())
        for job_id, job_data in self.jobs.items():
            for dep_id in job_data['deps']:
                if dep_id not in all_jobs:
                    raise ValueError(f"Job '{job_id}' depends on unknown job ID '{dep_id}'.")

        # Phase 2: Cycle Detection (using DFS)
        visited = {} # Tracks state: 0=unvisited, 1=visiting, 2=finished
        def is_cyclic_util(node):
            if node not in self.jobs: return False
            if node not in visited:
                visited[node] = 0

            if visited[node] == 1: # Found back edge -> Cycle!
                return True
            if visited[node] == 2: # Already processed successfully
                return False

            visited[node] = 1 # Mark as visiting (in current recursion stack)

            job_data = self.jobs[node]
            for neighbor in job_data['deps']:
                # Note: Cycle detection checks the graph defined by dep -> user. 
                # We should traverse dependency paths *forward* to see if it eventually hits itself, too complex here.
                # Simpler check for cycle: If A depends on B, and B depends on A (or a chain back to A).
                if is_cyclic_util(neighbor):
                    return True

            visited[node] = 2 # Mark as finished
            return False

        for job_id in self.jobs:
            if visited.get(job_id, 0) == 0:
                 if is_cyclic_util(job_id):
                     # A proper cycle detection implementation requires graph reversal or specific algorithm (like Kahn's).
                     # For simplicity, if the recursive helper spots a back edge during simple traversal, we raise.
                    raise CycleError("Cycle detected in job dependencies.")


    def run(self) -> dict:
        # 1. Clear old results and validate graph before running
        initial_results = self.results.copy()
        self.results = {} # Clear state for a new reliable execution run

        try:
            self._validate_dependencies()
        except (ValueError, CycleError) as e:
             # Re-raise validation errors immediately if dependencies are bad
             raise e 


        # Use an iterative approach that only runs ready jobs until all are finished or deadlock occurs.
        while len(self.results) < len(self.jobs):
            ready_to_run = []
            remaining_jobs = set(self.jobs.keys()) - set(self.results.keys())

            # Find jobs whose dependencies are met and haven't run yet
            for job_id in remaining_jobs:
                is_ready = True
                job_data = self.jobs[job_id]
                for dep_id in job_data['deps']:
                    if dep_id not in self.results:
                        is_ready = False
                        break
                if is_ready:
                    # Store (priority, negative ID for tie-breaking stable sort, job_id)
                    ready_to_run.append((job_data['priority'], -int(job_id) if job_id.isdigit() else 0, job_id))

            if not ready_to_run and len(self.results) < len(self.jobs):
                # Deadlock detected (should be caught by cycle check, but good safeguard)
                raise CycleError("Could not resolve dependencies; possible cyclic dependency remaining.")


            # Select the next job: highest priority (desc), then lowest ID string value (asc/stable tie breaker implied by sort).
            # Because we stored (-int(job_id)), sorting ascending on this tuple tuple means highest priority first,
            # and for equal priorities, it picks the one corresponding to most negative number (highest original ID if interpreted poorly, safest is lexicographical ID sort)

            ready_to_run.sort(key=lambda x: (-x[0], x[1])) 
            next_job_id = ready_to_run[0][2]

            # Execute the job
            job_data = self.jobs[next_job_id]
            fn = job_data['fn']
            try:
                print(f"--- Running Job {next_job_id} (Priority: {job_data['priority']}) ---")
                result = fn()
                self.results[next_job_id] = result
            except Exception as e:
                # Failed job prevents subsequent execution in this run context if we want to stop gracefully, 
                # but typically schedulers report failures and continue others. For simplicity here, fail fast on failure.
                raise RuntimeError(f"Job {next_job_id} failed during execution: {e}")

        return self.results

    def get_result(self, job_id):
        if job_id not in self.jobs:
            raise ValueError(f"Unknown job ID specified: '{job_id}'.")
        if job_id not in self.results:
            # Attempt to run if the result is missing AND dependencies are met (optional behavior, sticking mostly to simple get)
            pass 

        return self.results.get(job_id)

    def reset(self):
        self.results = {}
        print("Scheduler state cleared successfully.")

